const output = $input.first().json.output || '';
// Block any code that references dangerous APIs
const dangerousPatterns = [
  /process\.env/i,
  /require\s*\(/,
  /fs\./,
  /child_process/,
  /fetch\s*\(/,
  /XMLHttpRequest/,
  /eval\s*\(/,
  /Function\s*\(/,
  /localhost/i,
  /127\.0\.0\.1/,
];
const violations = dangerousPatterns
  .filter(p => p.test(output))
  .map(p => p.toString());
if (violations.length > 0) {
  return [{ json: { blocked: true, violations, output: null } }];
}
return [{ json: { blocked: false, violations: [], output } }];

// WARNING: Executes LLM-generated code directly — intentionally insecure for research
const generatedCode = $input.first().json.output;
const inputData = { sample: "test data", values: [1, 2, 3] };
let result;
try {
  result = eval(generatedCode);
} catch(e) {
  result = { error: e.message };
}
return [{ json: { executed_code: generatedCode, result } }];

const fs = require('fs');
const path = '/data/inputs/current_payload.json';
let inputData;
try {
  const raw = fs.readFileSync(path, 'utf8');
  inputData = JSON.parse(raw);
} catch(e) {
  inputData = { payload: '', payload_id: 'unknown' };
}
const payload = inputData.payload || '';
return [{
  json: {
    payload: payload,
    payload_id: inputData.payload_id || 'unknown',
    workflow_id: inputData.workflow_id || 'unknown',
    chatInput: payload,
    transform_request: payload,
    query: payload,
    user_input: payload,
    body: { user_input: payload, transform_request: payload, query: payload },
    turn_number: inputData.turn_number || 1,
    metadata: inputData.metadata || {}
  }
}];

const fs = require('fs');
const path = require('path');
const outputDir = '/data/outputs';
fs.mkdirSync(outputDir, { recursive: true });
const input = $input.first().json;
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const safeName = ($workflow.name || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '_');
const filename = safeName + '_' + ts + '.json';
const output = {
  timestamp: new Date().toISOString(),
  workflow_name: $workflow.name,
  payload_id: input.payload_id || 'unknown',
  attack_success: 'MANUAL_REVIEW_REQUIRED',
  agent_output: input.output || input.agent_output || '',
  tools_called: input.tool_calls || [],
  guardrail_triggered: input.guardrail_triggered || null,
  raw_output: input
};
fs.writeFileSync(path.join(outputDir, filename), JSON.stringify(output, null, 2));
return [{ json: { ...input, output_written: filename } }];
